import {
    InputTranslation,
    InputType,
    InputValidationAttribute,
    InputValidator,
    NumberInputType,
    URValidatorFn,
    VirtualKeyboardLayout,
} from './ur-field.model';

export const SelectedInput = {
    VALUE: 'VALUE',
    VARIABLE: 'VARIABLE',
    EXPRESSION: 'EXPRESSION',
} as const;

export type SelectedType = keyof typeof SelectedInput;

export type ValueType = string | number;

export interface TabInputValue {
    selectedType: SelectedType;
    value: ValueType;
}

export const TAB_INPUT_VALUE_TYPES = [
    'string',
    'integer',
    'float',
    'boolean',
    'pose',
    'matrix',
    'array',
    'waypoint',
    'grid',
    'timer',
    'profile',
    'frame',
] as const;

export type TabInputValueType = (typeof TAB_INPUT_VALUE_TYPES)[number];

export interface TabInputVariable {
    name: string;
    valueType: TabInputValueType;
    suppressed?: boolean;
}

/**
 * These are insertables that can be added to the current expression in
 * the expression tab. They will typically be entries in a dropdown
 * @property label This is what is shown in the dropdown.
 * @property value This is what will be inserted, if different to the label
 * @property details For grouping in the dropdown
 */
export interface TabInputInsertable {
    label: string;
    value?: string;
    details?: string;
}

/**
 * All the insertables
 */
export interface TabInputInsertableModel {
    inputs: TabInputInsertable[];
    outputs: TabInputInsertable[];
    builtins: TabInputInsertable[];
    functions: TabInputInsertable[];
    variables: TabInputVariable[];
}

export interface TabInputData {
    keyboardLayout?: VirtualKeyboardLayout;
    label: string;
    message?: string;
    inputLabel: string;
    placeholder: string;
    positiveDigitsOnly?: boolean;
    precision?: number;
    step?: number;
    tabs: Array<SelectedType>;
    tabInputValue: TabInputValue;
    title?: string;
    translations: InputTranslation;
    type: InputType | NumberInputType;
    unit?: string;
    valid?: boolean;
    validators?: InputValidator[] | URValidatorFn[];
    /**
     * @deprecated Temporary flag to explicitly specify validator format.
     * - true: All validators are URValidatorFn (new format)
     * - false/undefined: All validators are InputValidator (old format, default)
     *
     * This flag will be removed in the future once all validators are migrated to URValidatorFn.
     */
    useStandardValidators?: boolean;
    warningValidator?: URValidatorFn;
    validation?: InputValidationAttribute;
    valueType?: TabInputValueType | TabInputValueType[];
    variables?: TabInputVariable[];
    insertables?: TabInputInsertableModel;
}
export interface TabInputReturnData {
    selectedType: SelectedType;
    valid: boolean;
    value: string | number;
}
