import { AbstractControl, FormControlStatus, ValidationErrors } from '@angular/forms';
import { Observable } from 'rxjs';
import { Key } from 'ts-key-enum';
import { CloseReasonType } from './ur-dialog.model';

/**
 * @deprecated
 * See {@link URValidationFn} for the new type.
 */
export type InputValidatorMessage = { message: string; validationType: 'error' | 'warning' };

/**
 * @deprecated
 * This type is deprecated and should be replaced with URValidationFn.
 * See {@link URValidationFn} for the new type.
 */
export type InputValidator<T extends string | number = string | number> = (
    value: T,
) => string | InputValidatorMessage | null | Promise<string | InputValidatorMessage | null>;

export type URValidationResponse = ValidationErrors | string | null;
export type URValidatorFn = (
    control: AbstractControl,
) => URValidationResponse | Promise<URValidationResponse> | Observable<URValidationResponse>;

export type InputValidationAttribute = {
    minLength?: number; // the minimum and maximum length of textual data (strings)
    maxLength?: number; // the minimum and maximum length of textual data (strings)
    maxDecimalLength?: number; // the maximum decimal length value of numerical input types
    min?: number; // the minimum and maximum values of numerical input types
    max?: number; // the minimum and maximum values of numerical input types
    pattern?: string; // a regular expression that defines a pattern the entered data needs to follow.
    required?: boolean; // whether a form field needs to be filled in before the form can be submitted.
    type?: boolean; // should check for type mismatch
};
export interface InputTranslation {
    patternMismatchMessage?: string;
    requiredValidationMessage?: string;
    tooLongMessage?: string;
    tooShortMessage?: string;
    typeMismatchMessage?: string;
    rangeOverflowMessage?: string;
    rangeUnderflowMessage?: string;
    confirmMessage?: string;
}

export type AllowedKeys = {
    dot: string;
    dash: string;
    plus: string;
    backspace: Key.Backspace;
    arrowUp: Key.ArrowUp;
    arrowDown: Key.ArrowDown;
    arrowRight: Key.ArrowRight;
    arrowLeft: Key.ArrowLeft;
    home: Key.Home;
    end: Key.End;
    tab: Key.Tab;
    del: Key.Delete;
};

export const getAllowedKeys = (): string[] => {
    const allowedKeys: AllowedKeys = {
        dot: '.',
        arrowDown: Key.ArrowDown,
        arrowLeft: Key.ArrowLeft,
        arrowRight: Key.ArrowRight,
        arrowUp: Key.ArrowUp,
        home: Key.Home,
        end: Key.End,
        dash: '-',
        plus: '+',
        tab: Key.Tab,
        backspace: Key.Backspace,
        del: Key.Delete,
    };

    return [...Object.values(allowedKeys)];
};

export interface DialogInputData {
    charLimit?: number;
    currentValue?: string | number;
    keyboardLayout?: VirtualKeyboardLayout;
    label: string;
    message?: string;
    placeholder?: string;
    precision?: number;
    positiveDigitsOnly?: boolean;
    step?: number;
    title?: string;
    translations?: InputTranslation;
    type: InputType | NumberInputType;
    unit?: string;
    uid?: string;
    value?: string | number;
    validators?: InputValidator[];
    validation?: InputValidationAttribute;
    valid?: boolean;
    showClearIcon?: boolean;
    onBeforeClose?: (value: string, reason?: CloseReasonType) => string | null | Promise<string | null>;
}

export interface ValidationChangeEvent {
    status: FormControlStatus;
    errors?: ValidationErrors;
}

export interface DialogInputReturnData {
    value: string;
    valid: boolean;
}

/**
 * numeric-fixed: only numbers, no decimal point, no negative numbers
 * numeric-fixed-positive: only numbers, no decimal point, only positive numbers
 * numeric-free: numbers, decimal point, negative numbers
 * numeric-free-positive: numbers, decimal point, only positive numbers
 * alpha-numeric: numbers, letters, special characters
 */
export type VirtualKeyboardLayout =
    | 'numeric-fixed'
    | 'numeric-fixed-positive'
    | 'numeric-free'
    | 'numeric-free-positive'
    | 'alpha-numeric'
    | 'numeric-symbols';

export type InputType = 'email' | 'password' | 'search' | 'text' | 'url';
export type NumberInputType = 'number';

export default {};
