import { Injector, ViewContainerRef } from '@angular/core';

export const DialogSize = {
    TAKEOVER: 'TAKEOVER',
    XXL: 'XXL',
    XL: 'XL',
    LARGE: 'LARGE',
    DEFAULT: 'DEFAULT',
    SMALL: 'SMALL',
    XSMALL: 'XSMALL',
} as const;

export type DialogSizeType = keyof typeof DialogSize;
export interface GenericDialogOptions {
    dialogSize?: DialogSizeType;
    title?: string;
    icon?: string;
    showHeader?: boolean;
    showFooter?: boolean;
    confirmText?: string;
    cancelText?: string;
    raiseForKeyboard?: boolean;
    disableClose?: boolean;
}
export type DialogCloseEvent = {
    $event: Event;
    reason: CloseReasonType;
};
export type PortalCloseEvent = {
    id: string;
    customData: CloseDialog<unknown>;
};

export const CloseReason = {
    CANCELLED: 'CANCELLED',
    DESTROYED: 'DESTROYED',
    CONFIRMED: 'CONFIRMED',
    UNKNOWN: 'UNKNOWN',
} as const;
export type CloseReasonType = keyof typeof CloseReason;

export interface CloseDialog<T> {
    reason: CloseReasonType;
    returnData?: T;
}

export enum SafetyModeError {
    NORMAL = 'NORMAL',
    REDUCED = 'REDUCED',
    PROTECTIVE_STOP = 'PROTECTIVE_STOP',
    RECOVERY = 'RECOVERY',
    SAFEGUARD_STOP = 'SAFEGUARD_STOP',
    SYSTEM_EMERGENCY_STOP = 'SYSTEM_EMERGENCY_STOP',
    ROBOT_EMERGENCY_STOP = 'ROBOT_EMERGENCY_STOP',
    VIOLATION = 'VIOLATION',
    FAULT = 'FAULT',
    VALIDATE_JOINT_ID = 'VALIDATE_JOINT_ID',
    UNDEFINED_SAFETY_MODE = 'UNDEFINED_SAFETY_MODE',
    AUTOMATIC_MODE_SAFEGUARD_STOP = 'AUTOMATIC_MODE_SAFEGUARD_STOP',
    SYSTEM_THREE_POSITION_ENABLING_STOP = 'SYSTEM_THREE_POSITION_ENABLING_STOP',
    TP_THREE_POSITION_ENABLING_STOP = 'TP_THREE_POSITION_ENABLING_STOP',
    IMMI_EMERGENCY_STOP = 'IMMI_EMERGENCY_STOP',
    IMMI_SAFEGUARD_STOP = 'IMMI_SAFEGUARD_STOP',
    PROFISAFE_WAITING_FOR_PARAMETERS = 'PROFISAFE_WAITING_FOR_PARAMETERS',
    PROFISAFE_AUTOMATIC_MODE_SAFEGUARD_STOP = 'PROFISAFE_AUTOMATIC_MODE_SAFEGUARD_STOP',
    PROFISAFE_SAFEGUARD_STOP = 'PROFISAFE_SAFEGUARD_STOP',
    PROFISAFE_EMERGENCY_STOP = 'PROFISAFE_EMERGENCY_STOP',
    BRAKE_PIN_FAILURE = 'BRAKE_PIN_FAILURE',
    SAFETY_API_SAFEGUARD_STOP = 'SAFETY_API_SAFEGUARD_STOP',
    SAFETY_PLANES_SAFEGUARD_STOP = 'SAFETY_PLANES_SAFEGUARD_STOP',
}
export type DialogError = {
    errorType: 'SAFETY_MODE' | 'RUNTIME' | string;
    errorCodes?: number[];
    safetyMode?: SafetyModeError;
};
export type LayerToken =
    | '--layer-error'
    | '--layer-popup'
    | '--layer-keyboard'
    | '--layer-notification'
    | '--layer-dropdown'
    | '--layer-modal'
    | '--layer-navigation'
    | '--layer-tooltip'
    | '--layer-tools'
    | '--layer-program-nodes'
    | '--layer-default'
    | '--layer-under';
export interface DialogConfig {
    // controlling layer of the dialog with a css variable
    layer?: LayerToken;
    panelClass?: string;
    error?: DialogError;
    hasBackdrop?: boolean;
    backdropClass?: string;
    disableClose?: boolean; // If dialog shouldn't have a close icon
    critical?: boolean; // If dialog is critical, and cannot be 'force closed'.
    size?: DialogSizeType;
    maxOpenDialogs?: number; // If dialog has limit on number of open dialogs.
    viewContainerRef?: ViewContainerRef;
    injector?: Injector;
}

export const DIALOG_KEYS = {
    LOCALSTORAGE: 'ur-portal-service',
    OPEN_EVENT: 'portalservice:open',
    CLOSE_EVENT: 'portalservice:close',
    UPDATE_EVENT: 'portalservice:update',
    CLOSE_BY_ID_EVENT: 'portalservice:close_own',
    CLOSE_BY_ERROR_TYPE_EVENT: 'portalservice:close_by_type',
} as const;
